import { Component, ViewChild } from '@angular/core';
import { CustomerListComponent } from './features/customer-list/customer-list.component';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.scss']
})
export class AppComponent {
  title = 'Customer Management';

  @ViewChild(CustomerListComponent)
  customerListComponent!: CustomerListComponent;

  onCustomerCreated(): void {
    this.customerListComponent.loadCustomers();
  }
}
<!-- App Shell -->
<header class="app-header">
  <div class="header-inner">
    <span class="logo">👤 Customer Management</span>
  </div>
</header>

<main class="app-main">
  <div class="container">
    <app-customer-form (customerCreated)="onCustomerCreated()"></app-customer-form>
    <app-customer-list></app-customer-list>
  </div>
</main>

<footer class="app-footer">
  <p>Customer Management System &copy; 2026</p>
</footer>
